#ifdef BLOCK_SIZE
#define LOCAL_BLOCK_SIZE BLOCK_SIZE
#else
#define LOCAL_BLOCK_SIZE 16
#endif

__kernel void 
lud_diagonal(__global float *m, __local float *shadow, int matrix_dim, int offset)
{
  int i, j;
  int array_offset = offset * matrix_dim + offset;

  for(i = 0; i < LOCAL_BLOCK_SIZE; i++){
    shadow[i * LOCAL_BLOCK_SIZE + get_local_id(0)] = m[array_offset + get_local_id(0)];
    array_offset += matrix_dim;
  }

  __syncthreads();

  for(i = 0; i < LOCAL_BLOCK_SIZE - 1; i++) {
    if (get_local_id(0) > i){
      for(j = 0; j < i; j++)
        shadow[get_local_id(0) * LOCAL_BLOCK_SIZE + i] -= shadow[get_local_id(0) * LOCAL_BLOCK_SIZE + j] * shadow[j * LOCAL_BLOCK_SIZE + i];
      shadow[get_local_id(0) * LOCAL_BLOCK_SIZE + i] /= shadow[i * LOCAL_BLOCK_SIZE + i];
    }

    __syncthreads();

    if (get_local_id(0) > i){
      for(j = 0; j < i + 1; j++)
        shadow[(i + 1) * LOCAL_BLOCK_SIZE + get_local_id(0)] -= shadow[(i + 1) * LOCAL_BLOCK_SIZE + j] * shadow[j * LOCAL_BLOCK_SIZE + get_local_id(0)];
    }
    __syncthreads();
  }

  array_offset = (offset + 1) * matrix_dim + offset;
  for(i = 1; i < LOCAL_BLOCK_SIZE; i++){
    m[array_offset + get_local_id(0)] = shadow[i * LOCAL_BLOCK_SIZE + get_local_id(0)];
    array_offset += matrix_dim;
  }
}

__kernel void
lud_perimeter(__global float *m, __local float *dia, __local float *peri_row, __local float *peri_col, int matrix_dim, int offset)
{
  int i, j, array_offset;
  int idx;

  if (get_local_id(0) < LOCAL_BLOCK_SIZE) {
    idx = get_local_id(0);

    array_offset = offset * matrix_dim + offset;
    for (i = 0; i < LOCAL_BLOCK_SIZE / 2; i++){
      dia[i * LOCAL_BLOCK_SIZE + idx] = m[array_offset + idx];
      array_offset += matrix_dim;
    }

    array_offset = offset * matrix_dim + offset;
    for (i = 0; i < LOCAL_BLOCK_SIZE; i++) {
      peri_row[i * LOCAL_BLOCK_SIZE + idx] = m[array_offset + (get_group_id(0) + 1) * LOCAL_BLOCK_SIZE + idx];
      array_offset += matrix_dim;
    }
  } else {
    idx = get_local_id(0) - LOCAL_BLOCK_SIZE;

    array_offset = (offset + LOCAL_BLOCK_SIZE / 2) * matrix_dim + offset;
    for (i = LOCAL_BLOCK_SIZE / 2; i < LOCAL_BLOCK_SIZE; i++){
      dia[i * LOCAL_BLOCK_SIZE + idx] = m[array_offset + idx];
      array_offset += matrix_dim;
    }

    array_offset = (offset + (get_group_id(0) + 1) * LOCAL_BLOCK_SIZE) * matrix_dim + offset;
    for (i = 0; i < LOCAL_BLOCK_SIZE; i++) {
      peri_col[idx * LOCAL_BLOCK_SIZE + i] = m[array_offset + idx];
      array_offset += matrix_dim;
    }
  }

  __syncthreads();

  if (get_local_id(0) < LOCAL_BLOCK_SIZE) { 
    idx = get_local_id(0);
    for(i = 1; i < LOCAL_BLOCK_SIZE; i++){
      for (j = 0; j < i; j++)
        peri_row[i * LOCAL_BLOCK_SIZE + idx] -= dia[i * LOCAL_BLOCK_SIZE + j] * peri_row[j * LOCAL_BLOCK_SIZE + idx];
    }
  } else { 
    idx = get_local_id(0) - LOCAL_BLOCK_SIZE;
    for(i = 0; i < LOCAL_BLOCK_SIZE; i++){
      for(j = 0; j < i; j++)
        peri_col[idx * LOCAL_BLOCK_SIZE + i] -= peri_col[idx * LOCAL_BLOCK_SIZE + j] * dia[j * LOCAL_BLOCK_SIZE + i];
      peri_col[idx * LOCAL_BLOCK_SIZE + i] /= dia[i * LOCAL_BLOCK_SIZE + i];
    }
  }

  __syncthreads();

  if (get_local_id(0) < LOCAL_BLOCK_SIZE) { 
    idx = get_local_id(0);
    array_offset = (offset + 1) * matrix_dim + offset;
    for(i = 1; i < LOCAL_BLOCK_SIZE; i++){
      m[array_offset + (get_group_id(0) + 1) * LOCAL_BLOCK_SIZE + idx] = peri_row[i * LOCAL_BLOCK_SIZE + idx];
      array_offset += matrix_dim;
    }
  } else { 
    idx = get_local_id(0) - LOCAL_BLOCK_SIZE;
    array_offset = (offset + (get_group_id(0) + 1) * LOCAL_BLOCK_SIZE) * matrix_dim + offset;
    for(i = 0; i < LOCAL_BLOCK_SIZE; i++){
      m[array_offset + idx] = peri_col[i * LOCAL_BLOCK_SIZE + idx];
      array_offset += matrix_dim;
    }
  }
}

__kernel void
lud_internal(__global float *m, __local float *peri_row, __local float *peri_col, int matrix_dim, int offset)
{
  int i;
  float sum;

  int global_row_id = offset + (get_group_id(1) + 1) * LOCAL_BLOCK_SIZE;
  int global_col_id = offset + (get_group_id(0) + 1) * LOCAL_BLOCK_SIZE;

  peri_row[get_local_id(1) * LOCAL_BLOCK_SIZE + get_local_id(0)] = m[(offset + get_local_id(1)) * matrix_dim + global_col_id + get_local_id(0)];
  peri_col[get_local_id(1) * LOCAL_BLOCK_SIZE + get_local_id(0)] = m[(global_row_id + get_local_id(1)) * matrix_dim + offset + get_local_id(0)];

  __syncthreads();

  sum = 0;
  for (i = 0; i < LOCAL_BLOCK_SIZE; i++)
    sum += peri_col[get_local_id(1) * LOCAL_BLOCK_SIZE + i] * peri_row[i * LOCAL_BLOCK_SIZE + get_local_id(0)];

  m[(global_row_id + get_local_id(1)) * matrix_dim + global_col_id + get_local_id(0)] -= sum;
}
